+import React from 'react';
+
+const InteractiveMap = ({ machines, onSelectMachine, user, selectedMachine }) => {
+  // ─── STANOKLAR KOORDINATALARI ───
+  // Asosiy blok: 60 ta stanok (qatorlar bo'yicha kamayib boradi)
+  // Gemini C kodi mantiqi: Row1=10, Row2=10, Row3=10, Row4=10, Row5=9, Row6=6, Row7=5
+  const generateMainBlock = () => {
+    const nodes = [];
+    const rowCounts = [10, 10, 10, 10, 9, 6, 5];
+    let currentId = 1;
+    const startY = 260;
+    const startX = 120;
+    const gapX = 56;
+    const gapY = 65;
+
+    rowCounts.forEach((count, rowIndex) => {
+      // O'ng tomondan boshlab chapga qarab joylashadi (C kodi kabi)
+      const rowOffset = (10 - count) * gapX;
+      for (let i = 0; i < count; i++) {
+        nodes.push({
+          id: currentId++,
+          x: startX + rowOffset + (i * gapX),
+          y: startY + (rowIndex * gapY)
+        });
+      }
+    });
+    return nodes;
+  };
+
+  // O'ng blok: 8 ta stanok (S61-S68)
+  const generateRightBlock = () => {
+    const nodes = [];
+    const startY = 260;
+    const startX = 770;
+    const gapY = 62;
+    for (let i = 0; i < 8; i++) {
+      nodes.push({
+        id: 61 + i,
+        x: startX,
+        y: startY + (i * gapY)
+      });
+    }
+    return nodes;
+  };
+
+  const allNodes = [...generateMainBlock(), ...generateRightBlock()];
+
+  return (
+    <div className="factory-bg">
+      {/* ═══ SVG: DEVORLAR VA XARITA STRUKTURASI ═══ */}
+      <svg
+        width="100%"
+        height="100%"
+        style={{ position: 'absolute', top: 0, left: 0, pointerEvents: 'none' }}
+      >
+        {/* Tashqi devorlar */}
+        <rect x="40" y="40" width="870" height="700" rx="4"
+          fill="none" stroke="#334155" strokeWidth="4" />
+
+        {/* Ichki vertikal bo'luvchi devor (Xomashyo ombori / Ip yigiruv) */}
+        <line x1="320" y1="40" x2="320" y2="220" stroke="#334155" strokeWidth="3" />
+
+        {/* Gorizontal bo'luvchi (Yuqori xonalar / Stanoklar maydoni) */}
+        <line x1="40" y1="220" x2="720" y2="220" stroke="#334155" strokeWidth="3" />
+
+        {/* O'ng blok devori (Texnolog ofisi ajratmasi) */}
+        <line x1="720" y1="40" x2="720" y2="740" stroke="#334155" strokeWidth="3" />
+
+        {/* Pastki o'ng burchak ajratma (Kiyinish xonalari) */}
+        <line x1="720" y1="550" x2="910" y2="550" stroke="#334155" strokeWidth="2" strokeDasharray="6,4" />
+
+        {/* Qiya devor (chap pastki burchak - C kodi mantiqi) */}
+        <line x1="40" y1="550" x2="200" y2="740" stroke="#334155" strokeWidth="3" />
+
+        {/* ═══ EVAKUATSIYA YO'LLARI (Yashil strelkalar) ═══ */}
+        {/* Asosiy gorizontal yo'lak */}
+        <line x1="100" y1="240" x2="710" y2="240" stroke="#22c55e" strokeWidth="2.5"
+          strokeDasharray="12,6" opacity="0.6" />
+        <polygon points="710,234 722,240 710,246" fill="#22c55e" opacity="0.6" />
+
+        {/* Vertikal yo'lak (o'ng tomonga chiqish) */}
+        <line x1="710" y1="240" x2="710" y2="80" stroke="#22c55e" strokeWidth="2.5"
+          strokeDasharray="12,6" opacity="0.6" />
+        <polygon points="704,80 710,68 716,80" fill="#22c55e" opacity="0.6" />
+
+        {/* Pastki yo'lak */}
+        <line x1="200" y1="700" x2="710" y2="700" stroke="#22c55e" strokeWidth="2"
+          strokeDasharray="8,6" opacity="0.4" />
+        <polygon points="710,694 720,700 710,706" fill="#22c55e" opacity="0.4" />
+
+        {/* Stanoklar orasidagi yo'laklar (vertikal) */}
+        <line x1="350" y1="250" x2="350" y2="680" stroke="#22c55e" strokeWidth="1.5"
+          strokeDasharray="6,8" opacity="0.3" />
+        <line x1="530" y1="250" x2="530" y2="680" stroke="#22c55e" strokeWidth="1.5"
+          strokeDasharray="6,8" opacity="0.3" />
+      </svg>
+
+      {/* ═══ XONALAR NOMLARI ═══ */}
+      <div className="zone-label" style={{ top: '110px', left: '100px' }}>
+        XOMASHYO OMBORI
+      </div>
+      <div className="zone-label" style={{ top: '110px', left: '440px' }}>
+        IP YIGIRUV XONASI
+      </div>
+      <div className="zone-label" style={{ top: '110px', left: '770px', fontSize: '0.75rem' }}>
+        TEXNOLOG OFISI
+      </div>
+      <div className="zone-label" style={{ top: '600px', left: '770px', fontSize: '0.7rem' }}>
+        KIYINISH XONALARI
+      </div>
+      <div className="zone-label" style={{ top: '620px', left: '80px', fontSize: '0.7rem', transform: 'rotate(-25deg)' }}>
+        ZAPAS YO'LAK
+      </div>
+
+      {/* ═══ CHIQISH BELGILARI ═══ */}
+      <div className="chiqish-label" style={{ top: '8px', left: '200px' }}>▲ CHIQISH</div>
+      <div className="chiqish-label" style={{ top: '8px', left: '520px' }}>▲ CHIQISH</div>
+      <div className="chiqish-label" style={{ top: '8px', left: '810px' }}>▲ CHIQISH</div>
+
+      {/* ═══ YONG'IN O'CHIRGICHLARI ═══ */}
+      <div style={{ position: 'absolute', top: '225px', left: '48px', color: '#ef4444', fontSize: '1.2rem' }}>🧯</div>
+      <div style={{ position: 'absolute', top: '225px', left: '325px', color: '#ef4444', fontSize: '1.2rem' }}>🧯</div>
+      <div style={{ position: 'absolute', top: '225px', left: '725px', color: '#ef4444', fontSize: '1.2rem' }}>🧯</div>
+      <div style={{ position: 'absolute', top: '700px', left: '450px', color: '#ef4444', fontSize: '1.2rem' }}>🧯</div>
+
+      {/* ═══ STANOKLAR ═══ */}
+      {allNodes.map((node) => {
+        const machineData = machines.find((m) => m.id === `S${node.id}`) || { baud: 0, remaining: 0, status: 'OFFLINE' };
+        const isConnected = machineData.baud > 0;
+        
+        // Status aniqlash
+        let statusClass = 'stopped';
+        let statusMsg = "ESP32 OFF (Aloqa yo'q)";
+        
+        if (machineData.status === 'OFFLINE') {
+          statusClass = 'stopped';
+          statusMsg = "ESP32 OFF (Aloqa yo'q)";
+        } else if (machineData.status === 'ESP_ONLINE_NO_SIGNAL') {
+          statusClass = 'searching';
+          statusMsg = "ESP32 ONLINE | RS485 SIGNAL YO'Q";
+        } else if (machineData.status === 'ASNOVA_EMPTY') {
+          statusClass = 'warning';
+          statusMsg = "STOP (Asnova tugadi)";
+        } else if (machineData.status === 'RUNNING') {
+          statusClass = 'running';
+          statusMsg = "ISHLAYAPTI";
+        }
+
+        const isRunning = statusClass === 'running';
+        const isFocused = selectedMachine?.id === `S${node.id}`;
+        
+        return (
+          <div
+            key={node.id}
+            className={`machine-node ${statusClass} ${isRunning ? 'pulse-neon' : ''} ${isFocused ? 'is-focused' : ''}`}
+            style={{ 
+              left: `${node.x}px`, 
+              top: `${node.y}px`
+            }}
+            onClick={() => onSelectMachine({ ...machineData, displayStatus: statusMsg, id: `S${node.id}` })}
+            title={`S${node.id} | ${statusMsg}`}
+          >
+            <div style={{ 
+              display: 'flex', 
+              flexDirection: 'column', 
+              alignItems: 'center', 
+              gap: '2px', 
+              position: 'relative' 
+            }}>
+              {isFocused && <div className="smart-pulse"></div>}
+              
+              {/* Stanok ikonkasi */}
+              <svg width="26" height="20" viewBox="0 0 24 24" fill="currentColor" 
+                style={{ opacity: isConnected ? 1 : 0.35 }}>
+                <path d="M2,14 L2,18 L22,18 L22,14 M4,14 L4,6 L20,6 L20,14 M6,10 L18,10 M2,8 L2,20 L22,20 L22,8 L20,8 L20,4 L4,4 L4,8 Z" />
+                <rect x="7" y="11" width="10" height="3" 
+                  opacity={isRunning ? 0.9 : 0.15} 
+                  className={isRunning ? 'shuttle-anim' : ''} />
+              </svg>
+              
+              {/* Stanok raqami */}
+              <span style={{ 
+                fontSize: '0.6rem', 
+                letterSpacing: '0.5px', 
+                fontWeight: 800,
+                lineHeight: 1
+              }}>
+                {node.id}
+              </span>
+            </div>
+          </div>
+        );
+      })}
+
+      {/* ═══ QATORLAR RAQAMLARI ═══ */}
+      {[0, 1, 2, 3, 4, 5, 6].map((row) => (
+        <div key={`row-${row}`} style={{
+          position: 'absolute',
+          left: '80px',
+          top: `${275 + row * 65}px`,
+          fontSize: '0.55rem',
+          color: '#475569',
+          fontWeight: 700,
+          fontFamily: 'monospace'
+        }}>
+          Q{row + 1}
+        </div>
+      ))}
+
+      {/* ═══ LEGENDA ═══ */}
+      <div style={{
+        position: 'absolute',
+        bottom: '12px',
+        right: '16px',
+        display: 'flex',
+        gap: '12px',
+        fontSize: '0.6rem',
+        fontWeight: 600,
+        opacity: 0.6
+      }}>
+        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
+          <span style={{ width: 8, height: 8, borderRadius: '50%', background: 'var(--neon-green)' }}></span>
+          Ishlayapti
+        </span>
+        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
+          <span style={{ width: 8, height: 8, borderRadius: '50%', background: 'var(--neon-red)' }}></span>
+          To'xtagan
+        </span>
+        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
+          <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#a855f7' }}></span>
+          Qidiruv
+        </span>
+        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
+          <span style={{ width: 8, height: 8, borderRadius: '50%', background: 'var(--neon-yellow)' }}></span>
+          Asnova yo'q
+        </span>
+      </div>
+    </div>
+  );
+};
+
+export default InteractiveMap;

