+import React from 'react';
+
+const InteractiveMap = ({ machines, onSelectMachine, user, selectedMachine }) => {
+
+  // ═══ STANOKLAR - ASCII chizma asosida ═══
+  const generateMainBlock = () => {
+    const nodes = [];
+    const w = 44, h = 32, padX = 8, padY = 12;
+    const gapX = w + padX; // 52
+    const gapY = h + padY; // 44
+    const rightEdge = 720;
+    const baseY = 280;
+    const rowCounts = [10, 10, 10, 10, 9, 6, 4];
+    let currentId = 1;
+
+    rowCounts.forEach((count, rowIndex) => {
+      const rowWidth = count * gapX;
+      const startX = rightEdge - rowWidth;
+      const y = baseY + rowIndex * gapY;
+      for (let i = 0; i < count; i++) {
+        nodes.push({ id: currentId++, x: startX + i * gapX, y, w, h });
+      }
+    });
+    return nodes;
+  };
+
+  const generateRightBlock = () => {
+    const nodes = [];
+    const w = 44, h = 32;
+    for (let i = 0; i < 8; i++) {
+      nodes.push({ id: 61 + i, x: 870, y: 280 + i * 50, w, h });
+    }
+    return nodes;
+  };
+
+  const allNodes = [...generateMainBlock(), ...generateRightBlock()];
+
+  // ═══ DEVORLAR ═══
+  const walls = [
+    // Tashqi devorlar
+    { x1: 30, y1: 30, x2: 960, y2: 30 },
+    { x1: 30, y1: 30, x2: 30, y2: 700 },
+    { x1: 960, y1: 30, x2: 960, y2: 700 },
+    { x1: 30, y1: 700, x2: 960, y2: 700 },
+    // Ichki devorlar
+    { x1: 280, y1: 30, x2: 280, y2: 230 },  // Xomashyo ombori devori
+    { x1: 30, y1: 230, x2: 720, y2: 230 },   // Ip yigiruv ajratmasi
+    { x1: 720, y1: 30, x2: 720, y2: 700 },   // Texnolog ofisi devori
+    { x1: 720, y1: 520, x2: 960, y2: 520 },  // Kiyinish xonalari
+    // Qiya devor (ZAPAS YO'LAK)
+    { x1: 30, y1: 500, x2: 180, y2: 700 },
+  ];
+
+  // ═══ YASHIL YO'LLAR ═══
+  const paths = [
+    // Gorizontal asosiy yo'lak
+    { x1: 180, y1: 620, x2: 700, y2: 620 },
+    // Vertikal chiqish yo'li
+    { x1: 700, y1: 620, x2: 700, y2: 50 },
+  ];
+
+  // ═══ YONG'IN O'CHIRGICHLAR ═══
+  const fireExtinguishers = [
+    { x: 40, y: 45 },
+    { x: 295, y: 45 },
+    { x: 295, y: 245 },
+    { x: 735, y: 245 },
+    { x: 500, y: 690 },
+  ];
+
+  // ═══ OG'OHLANTIRISH BELGILARI ═══
+  const warnings = [
+    { x: 735, y: 180 },
+    { x: 735, y: 350 },
+    { x: 735, y: 450 },
+    { x: 735, y: 600 },
+  ];
+
+  return (
+    <div className="factory-bg">
+      {/* SVG devorlar */}
+      <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
+        {walls.map((w, i) => (
+          <line key={`w${i}`} x1={w.x1} y1={w.y1} x2={w.x2} y2={w.y2}
+            stroke="#475569" strokeWidth="2" />
+        ))}
+        {/* Qiya devor qalinroq */}
+        <line x1="30" y1="500" x2="180" y2="700" stroke="#475569" strokeWidth="3" />
+
+        {/* Yashil yo'llar */}
+        {paths.map((p, i) => (
+          <g key={`p${i}`}>
+            <line x1={p.x1} y1={p.y1} x2={p.x2} y2={p.y2}
+              stroke="#22c55e" strokeWidth="3" strokeDasharray="8,4" />
+            {/* Strelka */}
+            <polygon
+              points={p.x1 === p.x2
+                ? `${p.x2},${p.y2} ${p.x2 - 6},${p.y2 + 12} ${p.x2 + 6},${p.y2 + 12}`
+                : `${p.x2},${p.y2} ${p.x2 - 12},${p.y2 - 6} ${p.x2 - 12},${p.y2 + 6}`}
+              fill="#22c55e" />
+          </g>
+        ))}
+      </svg>
+
+      {/* Xona nomlari */}
+      <div style={{ position: 'absolute', left: 80, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>XOMASHYO OMBORI</div>
+      <div style={{ position: 'absolute', left: 380, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>IP YIGIRUV XONASI</div>
+      <div style={{ position: 'absolute', left: 780, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>TEXNOLOG OFISI</div>
+      <div style={{ position: 'absolute', left: 50, top: 580, color: '#475569', fontSize: '0.65rem', fontWeight: 700, letterSpacing: '1px', transform: 'rotate(-45deg)' }}>ZAPAS YO'LAK</div>
+
+      {/* Kiyinish xonalari */}
+      <div style={{ position: 'absolute', left: 740, top: 420, color: '#64748b', fontSize: '0.55rem', fontWeight: 600 }}>Ayollar kiyim</div>
+      <div style={{ position: 'absolute', left: 740, top: 435, color: '#64748b', fontSize: '0.55rem', fontWeight: 600 }}>almashtirish</div>
+      <div style={{ position: 'absolute', left: 740, top: 470, color: '#64748b', fontSize: '0.55rem', fontWeight: 600 }}>Erkaklar kiyim</div>
+      <div style={{ position: 'absolute', left: 740, top: 485, color: '#64748b', fontSize: '0.55rem', fontWeight: 600 }}>almashtirish</div>
+
+      {/* CHIQISH belgilari */}
+      {[200, 500, 800].map((x, i) => (
+        <div key={`exit${i}`} style={{
+          position: 'absolute', left: x, top: 10,
+          background: '#22c55e', padding: '4px 14px', borderRadius: '6px',
+          fontSize: '0.65rem', fontWeight: 800, color: '#064e3b',
+          boxShadow: '0 0 10px rgba(34,197,94,0.3)'
+        }}>▲ CHIQISH</div>
+      ))}
+
+      {/* Yong'in o'chirgichlar */}
+      {fireExtinguishers.map((f, i) => (
+        <div key={`fire${i}`} style={{
+          position: 'absolute', left: f.x, top: f.y,
+          width: 18, height: 18, border: '2px solid #ef4444', borderRadius: '4px',
+          display: 'flex', alignItems: 'center', justifyContent: 'center',
+          fontSize: '0.55rem', fontWeight: 800, color: '#ef4444'
+        }}>!</div>
+      ))}
+
+      {/* Ogohlantirish belgilari */}
+      {warnings.map((w, i) => (
+        <div key={`warn${i}`} style={{
+          position: 'absolute', left: w.x, top: w.y,
+          fontSize: '1rem', color: '#fbbf24'
+        }}>⚠</div>
+      ))}
+
+      {/* Stanoklar */}
+      {allNodes.map((node) => {
+        const machineData = machines.find((m) => m.id === `S${node.id}`) || { baud: 0, remaining: 0, status: 'OFFLINE' };
+        const isConnected = machineData.baud > 0;
+
+        let statusClass = 'stopped';
+        let statusMsg = "ESP32 OFF (Aloqa yo'q)";
+
+        if (machineData.status === 'OFFLINE') {
+          statusClass = 'stopped';
+          statusMsg = "ESP32 OFF (Aloqa yo'q)";
+        } else if (machineData.status === 'ESP_ONLINE_NO_SIGNAL') {
+          statusClass = 'searching';
+          statusMsg = "ESP32 ONLINE | RS485 SIGNAL YO'Q";
+        } else if (machineData.status === 'ASNOVA_EMPTY') {
+          statusClass = 'warning';
+          statusMsg = "STOP (Asnova tugadi)";
+        } else if (machineData.status === 'RUNNING') {
+          statusClass = 'running';
+          statusMsg = "ISHLAYAPTI";
+        }
+
+        const isRunning = statusClass === 'running';
+        const isFocused = selectedMachine?.id === `S${node.id}`;
+
+        return (
+          <div
+            key={node.id}
+            className={`machine-node ${statusClass} ${isRunning ? 'pulse-neon' : ''} ${isFocused ? 'is-focused' : ''}`}
+            style={{ left: `${node.x}px`, top: `${node.y}px`, width: `${node.w}px`, height: `${node.h}px` }}
+            onClick={() => onSelectMachine({ ...machineData, displayStatus: statusMsg, id: `S${node.id}` })}
+            title={`S${node.id} | ${statusMsg}`}
+          >
+            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1px', position: 'relative' }}>
+              {isFocused && <div className="smart-pulse"></div>}
+              <svg width="22" height="16" viewBox="0 0 24 24" fill="currentColor"
+                style={{ opacity: isConnected ? 1 : 0.35 }}>
+                <path d="M2,14 L2,18 L22,18 L22,14 M4,14 L4,6 L20,6 L20,14 M6,10 L18,10 M2,8 L2,20 L22,20 L22,8 L20,8 L20,4 L4,4 L4,8 Z" />
+                <rect x="7" y="11" width="10" height="3"
+                  opacity={isRunning ? 0.9 : 0.15}
+                  className={isRunning ? 'shuttle-anim' : ''} />
+              </svg>
+              <span style={{ fontSize: '0.55rem', letterSpacing: '0.5px', fontWeight: 800, lineHeight: 1 }}>
+                {node.id}
+              </span>
+            </div>
+          </div>
+        );
+      })}
+    </div>
+  );
+};
+
+export default InteractiveMap;

